SELECT sensor_id AS sensorId, force_value AS forceValue, displacement_value AS displacementValue, calc_stress AS calcStress, verified_stress AS verifiedStress, verify_status AS verifyStatus, verify_remark AS verifyRemark, collect_time AS collectTime, calc_time AS calcTime, verify_time AS verifyTime FROM stress_data WHERE sensor_id = #{sensorId} AND deleted = 0 AND verify_status = 2
AND collect_time >= #{startTime}
AND collect_time <= #{endTime}
ORDER BY collect_time ASC LIMIT #{limit}

SELECT
sensor_id AS sensorId,
force_value AS forceValue,
displacement_value AS displacementValue,
collect_time AS collectTime
FROM stress_data
WHERE sensor_id = #{sensorId}
AND deleted = 0

    AND collect_time  >=  #{startTime}


    AND collect_time  <=  #{endTime}

ORDER BY collect_time ASC
LIMIT #{limit}
